1→/**
     2→ * @fileoverview The MarkdownSourceCode class.
     3→ * @author Nicholas C. Zakas
     4→ */
     5→
     6→//-----------------------------------------------------------------------------
     7→// Imports
     8→//-----------------------------------------------------------------------------
     9→
    10→import {
    11→	VisitNodeStep,
    12→	TextSourceCodeBase,
    13→	ConfigCommentParser,
    14→	Directive,
    15→} from "@eslint/plugin-kit";
    16→import { findOffsets } from "../util.js";
    17→
    18→//-----------------------------------------------------------------------------
    19→// Types
    20→//-----------------------------------------------------------------------------
    21→
    22→/** @typedef {import("mdast").Root} RootNode */
    23→/** @typedef {import("mdast").Node} MarkdownNode */
    24→/** @typedef {import("mdast").Html} HTMLNode */
    25→/** @typedef {import("@eslint/core").Language} Language */
    26→/** @typedef {import("@eslint/core").File} File */
    27→/** @typedef {import("@eslint/core").TraversalStep} TraversalStep */
    28→/** @typedef {import("@eslint/core").VisitTraversalStep} VisitTraversalStep */
    29→/** @typedef {import("@eslint/core").TextSourceCode} TextSourceCode */
    30→/** @typedef {import("@eslint/core").ParseResult<RootNode>} ParseResult */
    31→/** @typedef {import("@eslint/core").SourceLocation} SourceLocation */
    32→/** @typedef {import("@eslint/core").SourceRange} SourceRange */
    33→/** @typedef {import("@eslint/core").FileProblem} FileProblem */
    34→/** @typedef {import("@eslint/core").DirectiveType} DirectiveType */
    35→
    36→//-----------------------------------------------------------------------------
    37→// Helpers
    38→//-----------------------------------------------------------------------------
    39→
    40→const commentParser = new ConfigCommentParser();
    41→const configCommentStart =
    42→	/<!--\s*(eslint(?:-enable|-disable(?:(?:-next)?-line)?))(?:\s|-->)/u;
    43→const htmlComment = /<!--(.*?)-->/gsu;
    44→
    45→/**
    46→ * Represents an inline config comment in the source code.
    47→ */
    48→class InlineConfigComment {
    49→	/**
    50→	 * The comment text.
    51→	 * @type {string}
    52→	 */
    53→	value;
    54→
    55→	/**
    56→	 * The position of the comment in the source code.
    57→	 * @type {SourceLocation}
    58→	 */
    59→	position;
    60→
    61→	/**
    62→	 * Creates a new instance.
    63→	 * @param {Object} options The options for the instance.
    64→	 * @param {string} options.value The comment text.
    65→	 * @param {SourceLocation} options.position The position of the comment in the source code.
    66→	 */
    67→	constructor({ value, position }) {
    68→		this.value = value.trim();
    69→		this.position = position;
    70→	}
    71→}
    72→
    73→/**
    74→ * Extracts inline configuration comments from an HTML node.
    75→ * @param {HTMLNode} node The HTML node to extract comments from.
    76→ * @returns {Array<InlineConfigComment>} The inline configuration comments found in the node.
    77→ */
    78→function extractInlineConfigCommentsFromHTML(node) {
    79→	if (!configCommentStart.test(node.value)) {
    80→		return [];
    81→	}
    82→	const comments = [];
    83→
    84→	let match;
    85→
    86→	while ((match = htmlComment.exec(node.value))) {
    87→		if (configCommentStart.test(match[0])) {
    88→			const comment = match[0];
    89→
    90→			// calculate location of the comment inside the node
    91→			const start = {
    92→				...node.position.start,
    93→			};
    94→
    95→			const end = {
    96→				...node.position.start,
    97→			};
    98→
    99→			const {
   100→				lineOffset: startLineOffset,
   101→				columnOffset: startColumnOffset,
   102→			} = findOffsets(node.value, match.index);
   103→
   104→			start.line += startLineOffset;
   105→			start.column += startColumnOffset;
   106→			start.offset += match.index;
   107→
   108→			const commentLineCount = comment.split("\n").length - 1;
   109→
   110→			end.line = start.line + commentLineCount;
   111→			end.column =
   112→				commentLineCount === 0
   113→					? start.column + comment.length
   114→					: comment.length - comment.lastIndexOf("\n");
   115→			end.offset = start.offset + comment.length;
   116→
   117→			comments.push(
   118→				new InlineConfigComment({
   119→					value: match[1].trim(),
   120→					position: {
   121→						start,
   122→						end,
   123→					},
   124→				}),
   125→			);
   126→		}
   127→	}
   128→
   129→	return comments;
   130→}
   131→
   132→//-----------------------------------------------------------------------------
   133→// Exports
   134→//-----------------------------------------------------------------------------
   135→
   136→/**
   137→ * Markdown Source Code Object
   138→ */
   139→export class MarkdownSourceCode extends TextSourceCodeBase {
   140→	/**
   141→	 * Cached traversal steps.
   142→	 * @type {Array<VisitNodeStep>|undefined}
   143→	 */
   144→	#steps;
   145→
   146→	/**
   147→	 * Cache of parent nodes.
   148→	 * @type {WeakMap<MarkdownNode, MarkdownNode>}
   149→	 */
   150→	#parents = new WeakMap();
   151→
   152→	/**
   153→	 * Collection of HTML nodes. Used to find directive comments.
   154→	 * @type {Array<HTMLNode>}
   155→	 */
   156→	#htmlNodes = [];
   157→
   158→	/**
   159→	 * Collection of inline configuration comments.
   160→	 * @type {Array<InlineConfigComment>}
   161→	 */
   162→	#inlineConfigComments;
   163→
   164→	/**
   165→	 * The AST of the source code.
   166→	 * @type {RootNode}
   167→	 */
   168→	ast = undefined;
   169→
   170→	/**
   171→	 * Creates a new instance.
   172→	 * @param {Object} options The options for the instance.
   173→	 * @param {string} options.text The source code text.
   174→	 * @param {RootNode} options.ast The root AST node.
   175→	 */
   176→	constructor({ text, ast }) {
   177→		super({ ast, text });
   178→		this.ast = ast;
   179→
   180→		// need to traverse the source code to get the inline config nodes
   181→		this.traverse();
   182→	}
   183→
   184→	/**
   185→	 * Returns the parent of the given node.
   186→	 * @param {MarkdownNode} node The node to get the parent of.
   187→	 * @returns {MarkdownNode|undefined} The parent of the node.
   188→	 */
   189→	getParent(node) {
   190→		return this.#parents.get(node);
   191→	}
   192→
   193→	/**
   194→	 * Returns an array of all inline configuration nodes found in the
   195→	 * source code.
   196→	 * @returns {Array<InlineConfigComment>} An array of all inline configuration nodes.
   197→	 */
   198→	getInlineConfigNodes() {
   199→		if (!this.#inlineConfigComments) {
   200→			this.#inlineConfigComments = this.#htmlNodes.flatMap(
   201→				extractInlineConfigCommentsFromHTML,
   202→			);
   203→		}
   204→
   205→		return this.#inlineConfigComments;
   206→	}
   207→
   208→	/**
   209→	 * Returns an all directive nodes that enable or disable rules along with any problems
   210→	 * encountered while parsing the directives.
   211→	 * @returns {{problems:Array<FileProblem>,directives:Array<Directive>}} Information
   212→	 *      that ESLint needs to further process the directives.
   213→	 */
   214→	getDisableDirectives() {
   215→		const problems = [];
   216→		const directives = [];
   217→
   218→		this.getInlineConfigNodes().forEach(comment => {
   219→			// Step 1: Parse the directive
   220→			const {
   221→				label,
   222→				value,
   223→				justification: justificationPart,
   224→			} = commentParser.parseDirective(comment.value);
   225→
   226→			// Step 2: Validate the directive does not span multiple lines
   227→			if (
   228→				label === "eslint-disable-line" &&
   229→				comment.position.start.line !== comment.position.end.line
   230→			) {
   231→				const message = `${label} comment should not span multiple lines.`;
   232→
   233→				problems.push({
   234→					ruleId: null,
   235→					message,
   236→					loc: comment.position,
   237→				});
   238→				return;
   239→			}
   240→
   241→			// Step 3: Extract the directive value and create the Directive object
   242→			switch (label) {
   243→				case "eslint-disable":
   244→				case "eslint-enable":
   245→				case "eslint-disable-next-line":
   246→				case "eslint-disable-line": {
   247→					const directiveType = label.slice("eslint-".length);
   248→
   249→					directives.push(
   250→						new Directive({
   251→							type: /** @type {DirectiveType} */ (directiveType),
   252→							node: comment,
   253→							value,
   254→							justification: justificationPart,
   255→						}),
   256→					);
   257→				}
   258→
   259→				// no default
   260→			}
   261→		});
   262→
   263→		return { problems, directives };
   264→	}
   265→
   266→	/**
   267→	 * Traverse the source code and return the steps that were taken.
   268→	 * @returns {Iterable<TraversalStep>} The steps that were taken while traversing the source code.
   269→	 */
   270→	traverse() {
   271→		// Because the AST doesn't mutate, we can cache the steps
   272→		if (this.#steps) {
   273→			return this.#steps.values();
   274→		}
   275→
   276→		/** @type {Array<VisitNodeStep>} */
   277→		const steps = (this.#steps = []);
   278→
   279→		const visit = (node, parent) => {
   280→			// first set the parent
   281→			this.#parents.set(node, parent);
   282→
   283→			// then add the step
   284→			steps.push(
   285→				new VisitNodeStep({
   286→					target: node,
   287→					phase: 1,
   288→					args: [node, parent],
   289→				}),
   290→			);
   291→
   292→			// save HTML nodes
   293→			if (node.type === "html") {
   294→				this.#htmlNodes.push(node);
   295→			}
   296→
   297→			// then visit the children
   298→			if (node.children) {
   299→				node.children.forEach(child => {
   300→					visit(child, node);
   301→				});
   302→			}
   303→
   304→			// then add the exit step
   305→			steps.push(
   306→				new VisitNodeStep({
   307→					target: node,
   308→					phase: 2,
   309→					args: [node, parent],
   310→				}),
   311→			);
   312→		};
   313→
   314→		visit(this.ast);
   315→
   316→		return steps.values();
   317→	}
   318→}
   319→

