1→/**
     2→ * @fileoverview Processes Markdown files for consumption by ESLint.
     3→ * @author Brandon Mills
     4→ */
     5→
     6→//-----------------------------------------------------------------------------
     7→// Imports
     8→//-----------------------------------------------------------------------------
     9→
    10→import { fromMarkdown } from "mdast-util-from-markdown";
    11→
    12→//-----------------------------------------------------------------------------
    13→// Type Definitions
    14→//-----------------------------------------------------------------------------
    15→
    16→/** @typedef {import("./types.ts").Block} Block */
    17→/** @typedef {import("./types.ts").RangeMap} RangeMap */
    18→/** @typedef {import("mdast").Node} Node */
    19→/** @typedef {import("mdast").Parent} ParentNode */
    20→/** @typedef {import("mdast").Code} CodeNode */
    21→/** @typedef {import("mdast").Html} HtmlNode */
    22→/** @typedef {import("eslint").Linter.LintMessage} Message */
    23→/** @typedef {import("eslint").Rule.Fix} Fix */
    24→/** @typedef {import("eslint").AST.Range} Range */
    25→
    26→//-----------------------------------------------------------------------------
    27→// Helpers
    28→//-----------------------------------------------------------------------------
    29→
    30→const UNSATISFIABLE_RULES = new Set([
    31→	"eol-last", // The Markdown parser strips trailing newlines in code fences
    32→	"unicode-bom", // Code blocks will begin in the middle of Markdown files
    33→]);
    34→const SUPPORTS_AUTOFIX = true;
    35→
    36→const BOM = "\uFEFF";
    37→
    38→/**
    39→ * @type {Map<string, Block[]>}
    40→ */
    41→const blocksCache = new Map();
    42→
    43→/**
    44→ * Performs a depth-first traversal of the Markdown AST.
    45→ * @param {Node} node A Markdown AST node.
    46→ * @param {{[key: string]: (node?: Node) => void}} callbacks A map of node types to callbacks.
    47→ * @returns {void}
    48→ */
    49→function traverse(node, callbacks) {
    50→	if (callbacks[node.type]) {
    51→		callbacks[node.type](node);
    52→	} else {
    53→		callbacks["*"]();
    54→	}
    55→
    56→	const parent = /** @type {ParentNode} */ (node);
    57→
    58→	if (typeof parent.children !== "undefined") {
    59→		for (let i = 0; i < parent.children.length; i++) {
    60→			traverse(parent.children[i], callbacks);
    61→		}
    62→	}
    63→}
    64→
    65→/**
    66→ * Extracts `eslint-*` or `global` comments from HTML comments if present.
    67→ * @param {string} html The text content of an HTML AST node.
    68→ * @returns {string} The comment's text without the opening and closing tags or
    69→ *     an empty string if the text is not an ESLint HTML comment.
    70→ */
    71→function getComment(html) {
    72→	const commentStart = "<!--";
    73→	const commentEnd = "-->";
    74→	const regex = /^(eslint\b|global\s)/u;
    75→
    76→	if (
    77→		html.slice(0, commentStart.length) !== commentStart ||
    78→		html.slice(-commentEnd.length) !== commentEnd
    79→	) {
    80→		return "";
    81→	}
    82→
    83→	const comment = html.slice(commentStart.length, -commentEnd.length);
    84→
    85→	if (!regex.test(comment.trim())) {
    86→		return "";
    87→	}
    88→
    89→	return comment;
    90→}
    91→
    92→// Before a code block, blockquote characters (`>`) are also considered
    93→// "whitespace".
    94→const leadingWhitespaceRegex = /^[>\s]*/u;
    95→
    96→/**
